// ── Helpers ────────────────────────────────────────────────
function parseHigh(est) {
  if (!est) return 0;
  const nums = est.replace(/[$,]/g,"").split(/[–\-]/)
    .map(p=>parseFloat(p.trim())).filter(n=>!isNaN(n));
  return nums.length ? Math.max(...nums) : 0;
}
function parseLow(est) {
  if (!est) return 0;
  const nums = est.replace(/[$,]/g,"").split(/[–\-]/)
    .map(p=>parseFloat(p.trim())).filter(n=>!isNaN(n));
  return nums.length ? Math.min(...nums) : 0;
}
function custHigh(c) {
  return Math.max(0,...(c.shipments||[]).flatMap(s=>(s.items||[]).map(i=>parseHigh(i.estimate))));
}
function fmtPhone(p) {
  if (!p) return "";
  const d = p.replace(/\D/g,"");
  if (d.length===10) return `(${d.slice(0,3)}) ${d.slice(3,6)}-${d.slice(6)}`;
  return p;
}
function fmt$(n) { return n ? "$"+Number(n).toLocaleString() : "—"; }
function custPrimaryStage(c) {
  const order = ["purchase_complete","offer_made","accepted","inspected","received",
    "outbound_fulfilled","outbound_pending","ready_to_fulfill","estimate_only","dead"];
  const stages = (c.shipments||[]).map(s=>s.stage);
  return order.find(s=>stages.includes(s)) || "estimate_only";
}
function daysSince(ts) {
  if (!ts) return 999;
  return Math.floor((Date.now()-new Date(ts).getTime())/(1000*60*60*24));
}

// ── Storage ────────────────────────────────────────────────
const SK = "sg_crm_v3";
function getStore() { try { return JSON.parse(localStorage.getItem(SK)||"{}"); } catch { return {}; } }
function putStore(d) { try { localStorage.setItem(SK,JSON.stringify(d)); } catch {} }

function initCustomers() {
  const stored = getStore();
  const map = {};
  for (const c of SEED) {
    const k = c.custId;
    const s = stored[k];
    map[k] = s ? {
      ...c,
      contactLog: s.contactLog ?? [],
      notes: s.notes ?? "",
      shipments: s.shipments ?? c.shipments,
      deleted: s.deleted ?? false,
    } : { ...c };
  }
  // User-added records not in seed
  for (const [k,v] of Object.entries(stored)) {
    if (!map[k] && !v.deleted) map[k] = v;
  }
  return map;
}

function persist(map) {
  const out = {};
  for (const [k,v] of Object.entries(map)) {
    out[k] = { contactLog:v.contactLog, notes:v.notes, shipments:v.shipments, deleted:v.deleted??false };
  }
  putStore(out);
}

// ── Atoms ──────────────────────────────────────────────────
function Badge({ stage, sm }) {
  const c = SC[stage]||"#9E9E9E";
  return (
    <span style={{
      background:c+"18", color:c, border:`1px solid ${c}33`,
      borderRadius:4, padding:sm?"1px 5px":"2px 8px",
      fontSize:sm?9:11, fontWeight:700, whiteSpace:"nowrap"
    }}>{SL[stage]||stage}</span>
  );
}

function Btn({ children, onClick, v="ghost", disabled, style:st={} }) {
  const base = { border:"none", borderRadius:5, cursor:disabled?"not-allowed":"pointer",
    fontWeight:600, fontSize:12, padding:"5px 11px", opacity:disabled?0.5:1,
    transition:"opacity 0.1s" };
  const vars = {
    gold:   { background:G.gold, color:"#fff" },
    danger: { background:"#FFEBEE", color:G.red, border:`1px solid ${G.red}33` },
    ghost:  { background:"#F0EAE0", color:G.text, border:`1px solid ${G.border}` },
    green:  { background:"#E8F5E9", color:G.green, border:`1px solid ${G.green}33` },
    blue:   { background:"#E3F2FD", color:G.blue, border:`1px solid ${G.blue}33` },
  };
  return <button onClick={disabled?undefined:onClick}
    style={{...base,...vars[v],...st}}
    onMouseEnter={e=>!disabled&&(e.currentTarget.style.opacity="0.75")}
    onMouseLeave={e=>e.currentTarget.style.opacity="1"}
  >{children}</button>;
}

function Inp({ label, value, onChange, type="text", placeholder="", rows }) {
  const common = { width:"100%", boxSizing:"border-box", background:G.bg, color:G.text,
    border:`1px solid ${G.border}`, borderRadius:5, padding:"6px 10px", fontSize:13 };
  return (
    <div>
      {label && <div style={{color:G.muted,fontSize:11,marginBottom:3}}>{label}</div>}
      {rows
        ? <textarea value={value||""} onChange={onChange} rows={rows} placeholder={placeholder}
            style={{...common,resize:"vertical"}} />
        : <input type={type} value={value||""} onChange={onChange} placeholder={placeholder}
            style={common} />
      }
    </div>
  );
}

function Sel({ label, value, onChange, options }) {
  return (
    <div>
      {label && <div style={{color:G.muted,fontSize:11,marginBottom:3}}>{label}</div>}
      <select value={value||""} onChange={onChange} style={{
        width:"100%", boxSizing:"border-box", background:G.bg, color:G.text,
        border:`1px solid ${G.border}`, borderRadius:5, padding:"6px 10px", fontSize:13, cursor:"pointer"
      }}>
        {options.map(o=>typeof o==="string"
          ? <option key={o} value={o}>{SL[o]||o}</option>
          : <option key={o.v} value={o.v}>{o.l}</option>
        )}
      </select>
    </div>
  );
}

function ContactBtns({ customer, size="sm" }) {
  const ph = (customer.phone||"").replace(/\D/g,"");
  const p = size==="sm" ? "4px 8px" : "7px 13px";
  const fs = size==="sm" ? 12 : 13;
  const btn = (href,bg,color,label) => (
    <a href={href} style={{background:bg,color,border:`1px solid ${color}22`,
      borderRadius:4,padding:p,fontSize:fs,textDecoration:"none",fontWeight:600}}>
      {label}
    </a>
  );
  return (
    <div style={{display:"flex",gap:5,flexWrap:"wrap"}}>
      {ph && btn(`tel:${ph}`,"#E8F5E9",G.green,"📞")}
      {ph && btn(`sms:${ph}`,"#E3F2FD",G.blue,"💬")}
      {customer.email && btn(`mailto:${customer.email}`,"#F3E5F5","#6A1B9A","✉️")}
    </div>
  );
}

// ── PIN Gate ───────────────────────────────────────────────
function PinGate({ onUnlock }) {
  const [pin, setPin] = useState("");
  const [err, setErr] = useState(false);
  function submit() {
    if (pin==="5437") onUnlock();
    else { setErr(true); setPin(""); setTimeout(()=>setErr(false),700); }
  }
  return (
    <div style={{minHeight:"100vh",background:G.bg,display:"flex",
      alignItems:"center",justifyContent:"center",flexDirection:"column",gap:20}}>
      <div style={{textAlign:"center"}}>
        <div style={{fontSize:44}}>🤖</div>
        <div style={{color:G.gold,fontSize:22,fontWeight:800,letterSpacing:2}}>SNAPPY GOLD</div>
        <div style={{color:G.muted,fontSize:12}}>CRM v3</div>
      </div>
      <div style={{background:G.card,borderRadius:12,padding:28,
        boxShadow:"0 4px 20px rgba(0,0,0,0.1)",border:`1px solid ${G.border}`,
        display:"flex",flexDirection:"column",gap:12,alignItems:"center",
        animation:err?"shake 0.5s":undefined}}>
        <input autoFocus type="password" value={pin} maxLength={6}
          onChange={e=>setPin(e.target.value)} onKeyDown={e=>e.key==="Enter"&&submit()}
          placeholder="PIN"
          style={{background:G.bg,border:`2px solid ${err?G.red:G.gold}`,borderRadius:8,
            color:G.text,fontSize:22,padding:"10px 20px",textAlign:"center",
            letterSpacing:8,width:180}}
        />
        <Btn onClick={submit} v="gold" st={{width:"100%",padding:"9px 0",fontSize:14}}>Unlock</Btn>
        {err && <div style={{color:G.red,fontSize:12}}>Incorrect PIN</div>}
      </div>
      <style>{`@keyframes shake{0%,100%{transform:translateX(0)}20%,60%{transform:translateX(-8px)}40%,80%{transform:translateX(8px)}}`}</style>
    </div>
  );
}

// ── Shipment Card (in detail modal) ───────────────────────
function ShipmentCard({ ship, idx, onChange, onDelete, isOnly }) {
  const [open, setOpen] = useState(idx===0);
  const topItem = (ship.items||[]).find(i=>i.estimate)?.item || (ship.items||[])[0]?.item || "No items";
  const high = Math.max(0,...(ship.items||[]).map(i=>parseHigh(i.estimate)));
  const low  = Math.min(...(ship.items||[]).filter(i=>i.estimate).map(i=>parseLow(i.estimate)).filter(Boolean));

  function upd(f,v) { onChange({...ship,[f]:v}); }
  function updPurchase(f,v) { onChange({...ship,purchase:{...(ship.purchase||{}), [f]:v}}); }

  return (
    <div style={{border:`1px solid ${G.border}`,borderRadius:8,overflow:"hidden",marginBottom:8}}>
      <div style={{display:"flex",alignItems:"center",gap:10,padding:"10px 14px",
        background:"#FAF7F2",cursor:"pointer"}} onClick={()=>setOpen(o=>!o)}>
        <span>📦</span>
        <div style={{flex:1,minWidth:0}}>
          <div style={{fontSize:11,fontWeight:700,color:G.text}}>{ship.shipmentId}</div>
          <div style={{fontSize:11,color:G.muted,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{topItem}</div>
        </div>
        <Badge stage={ship.stage} sm />
        {high>0 && <span style={{color:G.gold,fontWeight:800,fontSize:13}}>{fmt$(high)}</span>}
        <span style={{color:G.muted,fontSize:11}}>{open?"▲":"▼"}</span>
      </div>

      {open && (
        <div style={{padding:14,display:"flex",flexDirection:"column",gap:12,background:G.card}}>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
            <Sel label="Stage" value={ship.stage} onChange={e=>upd("stage",e.target.value)} options={STAGES}/>
            <Sel label="Ship Type" value={ship.shippingType}
              onChange={e=>upd("shippingType",e.target.value)}
              options={[{v:"",l:"—"},{v:"kit",l:"Kit (mail)"},{v:"label",l:"Label (email)"}]}/>
            <Inp label="USPS Outbound Tracking (Pirateship)" value={ship.outboundTracking}
              onChange={e=>upd("outboundTracking",e.target.value)} placeholder="9400…"/>
            <Inp label="FedEx Return Tracking" value={ship.returnTracking}
              onChange={e=>upd("returnTracking",e.target.value)} placeholder="7922…"/>
          </div>

          {/* Purchase */}
          <div style={{background:"#F0FFF0",border:`1px solid ${G.green}33`,borderRadius:6,padding:10}}>
            <div style={{fontWeight:700,fontSize:11,color:G.green,marginBottom:8}}>Purchase Details</div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8}}>
              <Inp label="Purchase Price" type="number" value={ship.purchase?.price||""}
                onChange={e=>updPurchase("price",e.target.value)} placeholder="0"/>
              <Inp label="Appraised Value" type="number" value={ship.purchase?.appraised||""}
                onChange={e=>updPurchase("appraised",e.target.value)} placeholder="0"/>
              <Sel label="Payment" value={ship.purchase?.payment||"Zelle"}
                onChange={e=>updPurchase("payment",e.target.value)}
                options={[{v:"Zelle",l:"Zelle"},{v:"Cash",l:"Cash"},{v:"Check",l:"Check"},{v:"Venmo",l:"Venmo"},{v:"PayPal",l:"PayPal"}]}/>
            </div>
            <div style={{marginTop:8}}>
              <Inp label="Item Photos (Drive links)" value={ship.purchase?.photos||""}
                onChange={e=>updPurchase("photos",e.target.value)} placeholder="https://drive.google.com/…"/>
            </div>
          </div>

          {/* Items */}
          <div>
            <div style={{fontWeight:700,fontSize:11,color:G.text,marginBottom:6}}>
              Items ({(ship.items||[]).length})
              {(ship.items||[]).length>1 && high>0 && low>0 && low!==high &&
                <span style={{color:G.gold,fontWeight:400,marginLeft:8}}>{fmt$(low)} – {fmt$(high)}</span>
              }
            </div>
            {(ship.items||[]).map((item,i)=>{
              const h = parseHigh(item.estimate);
              const l = parseLow(item.estimate);
              const dupFlag = (ship.items||[]).filter(x=>x.item===item.item).length>1;
              return (
                <div key={i} style={{display:"flex",gap:8,alignItems:"flex-start",
                  padding:"7px 0",borderBottom:i<(ship.items||[]).length-1?`1px solid ${G.border}`:"none"}}>
                  {(item.photos||[]).length>0 && (
                    <div style={{display:"flex",gap:4,flexShrink:0}}>
                      {(item.photos||[]).map((ph,pi)=>(
                        <a key={pi} href={ph} target="_blank" rel="noreferrer"
                          style={{background:"#F5F0E8",borderRadius:4,padding:"3px 6px",
                            fontSize:14,textDecoration:"none",border:`1px solid ${G.border}`}}>
                          📷
                        </a>
                      ))}
                    </div>
                  )}
                  <div style={{flex:1,minWidth:0}}>
                    <div style={{fontSize:12,color:G.text}}>
                      {item.item}
                      {dupFlag && <span style={{fontSize:10,color:G.gold,marginLeft:6,
                        background:"#FFF8E1",padding:"1px 5px",borderRadius:3}}>dup</span>}
                    </div>
                    {item.estimate && (
                      <div style={{fontSize:13,fontWeight:700,color:G.gold}}>{item.estimate}</div>
                    )}
                  </div>
                </div>
              );
            })}
          </div>

          {!isOnly && (
            <div style={{display:"flex",justifyContent:"flex-end"}}>
              <Btn v="danger" onClick={onDelete}>Delete Shipment</Btn>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

// ── Merge Modal ────────────────────────────────────────────
function MergeModal({ customer, allCustomers, onMerge, onClose }) {
  const [search, setSearch] = useState("");
  const [target, setTarget] = useState(null);
  const [winner, setWinner] = useState("current"); // current | other

  const matches = useMemo(()=>{
    if (!search.trim()) return [];
    const q = search.toLowerCase();
    return Object.values(allCustomers).filter(c=>
      c.custId !== customer.custId && !c.deleted &&
      (c.name?.toLowerCase().includes(q)||c.email?.toLowerCase().includes(q))
    ).slice(0,8);
  },[search,allCustomers,customer]);

  function doMerge() {
    if (!target) return;
    const base = winner==="current" ? customer : target;
    const other = winner==="current" ? target : customer;
    const merged = {
      ...base,
      phone: base.phone || other.phone,
      address: base.address || other.address,
      source: base.source || other.source,
      shipments: [...(base.shipments||[]), ...(other.shipments||[])],
      contactLog: [...(base.contactLog||[]), ...(other.contactLog||[])].sort((a,b)=>new Date(b.ts)-new Date(a.ts)),
      notes: [base.notes, other.notes].filter(Boolean).join("\n"),
    };
    onMerge(merged, other.custId);
    onClose();
  }

  return (
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.5)",
      display:"flex",alignItems:"center",justifyContent:"center",zIndex:300,padding:24}}
      onClick={e=>e.target===e.currentTarget&&onClose()}>
      <div style={{background:G.card,borderRadius:12,width:"100%",maxWidth:520,
        padding:24,border:`1px solid ${G.border}`,boxShadow:"0 8px 32px rgba(0,0,0,0.15)"}}>
        <div style={{fontWeight:800,fontSize:16,color:G.text,marginBottom:16}}>Merge Customer</div>
        <div style={{marginBottom:12}}>
          <Inp label="Search for duplicate by name or email" value={search}
            onChange={e=>setSearch(e.target.value)} placeholder="Type to search…"/>
        </div>
        {matches.map(c=>(
          <div key={c.custId} onClick={()=>setTarget(c)} style={{
            padding:"8px 12px",borderRadius:6,marginBottom:4,cursor:"pointer",
            background:target?.custId===c.custId?"#E3F2FD":G.bg,
            border:`1px solid ${target?.custId===c.custId?G.blue:G.border}`
          }}>
            <div style={{fontWeight:700,fontSize:13}}>{c.name||"—"}</div>
            <div style={{fontSize:11,color:G.muted}}>{c.email} · {c.shipments?.length||0} shipments</div>
          </div>
        ))}
        {target && (
          <div style={{marginTop:16,padding:12,background:"#FFF8E1",
            border:`1px solid #F57F1733`,borderRadius:6}}>
            <div style={{fontWeight:700,fontSize:12,marginBottom:8}}>Which record wins? (name, email, address)</div>
            <div style={{display:"flex",gap:8}}>
              <label style={{display:"flex",gap:6,alignItems:"center",cursor:"pointer",fontSize:12}}>
                <input type="radio" checked={winner==="current"} onChange={()=>setWinner("current")}/>
                {customer.name||customer.email} (current)
              </label>
              <label style={{display:"flex",gap:6,alignItems:"center",cursor:"pointer",fontSize:12}}>
                <input type="radio" checked={winner==="other"} onChange={()=>setWinner("other")}/>
                {target.name||target.email}
              </label>
            </div>
            <div style={{fontSize:11,color:G.muted,marginTop:6}}>All shipments and contact logs will be combined.</div>
          </div>
        )}
        <div style={{display:"flex",gap:8,marginTop:16,justifyContent:"flex-end"}}>
          <Btn onClick={onClose}>Cancel</Btn>
          <Btn v="gold" onClick={doMerge} disabled={!target}>Merge Records</Btn>
        </div>
      </div>
    </div>
  );
}

// ── Customer Detail Modal ──────────────────────────────────
function CustomerDetail({ customer, allCustomers, onClose, onSave, onDelete }) {
  const [c, setC] = useState(JSON.parse(JSON.stringify(customer)));
  const [tab, setTab] = useState("info");
  const [logText, setLogText] = useState("");
  const [confirmDel, setConfirmDel] = useState(false);
  const [showMerge, setShowMerge] = useState(false);

  const high = custHigh(c);

  function save() { onSave(c); onClose(); }

  function updateShipment(i, upd) {
    const ships = [...c.shipments];
    ships[i] = upd;
    setC({...c, shipments:ships});
  }
  function deleteShipment(i) {
    setC({...c, shipments:c.shipments.filter((_,idx)=>idx!==i)});
  }
  function addShipment() {
    setC({...c, shipments:[...c.shipments, {
      shipmentId:`SHP-NEW-${Date.now()}`,
      stage:"estimate_only", shippingType:"", outboundTracking:"",
      returnTracking:"", items:[], purchase:null, notes:""
    }]});
  }
  function logContact() {
    if (!logText.trim()) return;
    setC({...c, contactLog:[{ts:new Date().toISOString(),text:logText.trim()},...(c.contactLog||[])]});
    setLogText("");
  }
  function handleMerge(merged, deletedId) {
    onSave(merged);
    onDelete(deletedId);
    onClose();
  }

  const T = (t,label) => (
    <button onClick={()=>setTab(t)} style={{background:"none",border:"none",
      padding:"10px 16px",cursor:"pointer",fontSize:13,fontWeight:600,
      color:tab===t?G.gold:G.muted,
      borderBottom:tab===t?`2px solid ${G.gold}`:"2px solid transparent"}}>
      {label}
    </button>
  );

  return (
    <>
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.35)",
      display:"flex",alignItems:"flex-start",justifyContent:"center",
      zIndex:200,padding:"20px 16px",overflowY:"auto"}}
      onClick={e=>e.target===e.currentTarget&&onClose()}>
      <div style={{background:G.card,borderRadius:12,width:"100%",maxWidth:700,
        boxShadow:"0 8px 40px rgba(0,0,0,0.15)",border:`1px solid ${G.border}`}}>

        {/* Header */}
        <div style={{padding:"16px 22px",borderBottom:`1px solid ${G.border}`,
          background:G.bg,borderRadius:"12px 12px 0 0"}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
            <div>
              <div style={{color:G.text,fontSize:19,fontWeight:800}}>
                {c.name||<span style={{color:G.muted}}>Unknown</span>}
              </div>
              <div style={{color:G.muted,fontSize:12,marginTop:1}}>{c.email}</div>
              {c.phone&&<div style={{color:G.muted,fontSize:12}}>{fmtPhone(c.phone)}</div>}
            </div>
            <div style={{display:"flex",gap:8,alignItems:"center"}}>
              {high>0 && (
                <div style={{textAlign:"right"}}>
                  <div style={{color:G.gold,fontSize:17,fontWeight:800}}>{fmt$(high)}</div>
                  <div style={{color:G.muted,fontSize:10}}>est. high</div>
                </div>
              )}
              <button onClick={onClose} style={{background:"transparent",
                border:`1px solid ${G.border}`,color:G.muted,
                borderRadius:6,padding:"5px 10px",cursor:"pointer",fontSize:16}}>✕</button>
            </div>
          </div>
          <div style={{marginTop:10,display:"flex",gap:8,alignItems:"center",flexWrap:"wrap"}}>
            <ContactBtns customer={c} size="md"/>
            {[...new Set((c.shipments||[]).map(s=>s.stage))].map(s=><Badge key={s} stage={s} sm/>)}
          </div>
        </div>

        {/* Tabs */}
        <div style={{display:"flex",borderBottom:`1px solid ${G.border}`,padding:"0 14px"}}>
          {T("info","Info")}
          {T("shipments",`Shipments (${(c.shipments||[]).length})`)}
          {T("contact",`Log (${(c.contactLog||[]).length})`)}
        </div>

        <div style={{padding:20}}>
          {/* INFO TAB */}
          {tab==="info" && (
            <div style={{display:"flex",flexDirection:"column",gap:12}}>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
                <Inp label="Name" value={c.name} onChange={e=>setC({...c,name:e.target.value})}/>
                <Inp label="Phone" value={c.phone} onChange={e=>setC({...c,phone:e.target.value})}/>
                <Inp label="Email" value={c.email} onChange={e=>setC({...c,email:e.target.value})}/>
                <Inp label="Source" value={c.source} onChange={e=>setC({...c,source:e.target.value})}/>
              </div>
              <Inp label="Address" value={c.address} onChange={e=>setC({...c,address:e.target.value})}/>
              <Inp label="Notes" value={c.notes} onChange={e=>setC({...c,notes:e.target.value})} rows={3}/>

              <div style={{display:"flex",gap:8,flexWrap:"wrap",justifyContent:"space-between",alignItems:"center"}}>
                <div style={{display:"flex",gap:8}}>
                  <Btn v="gold" onClick={save}>Save Changes</Btn>
                  <Btn v="blue" onClick={()=>setShowMerge(true)}>Merge…</Btn>
                </div>
                <div>
                  {!confirmDel
                    ? <Btn v="danger" onClick={()=>setConfirmDel(true)}>Delete Customer</Btn>
                    : <div style={{display:"flex",gap:8,alignItems:"center"}}>
                        <span style={{fontSize:12,color:G.red}}>Sure?</span>
                        <Btn v="danger" onClick={()=>{onDelete(c.custId);onClose();}}>Yes, Delete</Btn>
                        <Btn onClick={()=>setConfirmDel(false)}>Cancel</Btn>
                      </div>
                  }
                </div>
              </div>
            </div>
          )}

          {/* SHIPMENTS TAB */}
          {tab==="shipments" && (
            <div>
              {(c.shipments||[]).map((s,i)=>(
                <ShipmentCard key={s.shipmentId} ship={s} idx={i}
                  onChange={upd=>updateShipment(i,upd)}
                  onDelete={()=>deleteShipment(i)}
                  isOnly={(c.shipments||[]).length===1}
                />
              ))}
              <Btn v="ghost" onClick={addShipment} st={{width:"100%",padding:"9px 0",marginBottom:12}}>
                + Add Shipment
              </Btn>
              <Btn v="gold" onClick={save}>Save Shipments</Btn>
            </div>
          )}

          {/* CONTACT LOG TAB */}
          {tab==="contact" && (
            <div style={{display:"flex",flexDirection:"column",gap:12}}>
              <div style={{display:"flex",gap:8}}>
                <textarea value={logText} onChange={e=>setLogText(e.target.value)} rows={2}
                  placeholder="Log contact attempt, outcome, note…"
                  style={{flex:1,background:G.bg,color:G.text,border:`1px solid ${G.border}`,
                    borderRadius:5,padding:"7px 10px",fontSize:13,resize:"none",boxSizing:"border-box"}}
                />
                <Btn v="gold" onClick={logContact} st={{alignSelf:"flex-end",padding:"8px 14px"}}>Log</Btn>
              </div>
              <div>
                {(c.contactLog||[]).length===0 &&
                  <div style={{color:G.muted,textAlign:"center",padding:24,fontSize:13}}>No contact logged</div>}
                {(c.contactLog||[]).map((e,i)=>(
                  <div key={i} style={{background:G.bg,borderRadius:6,padding:"8px 12px",
                    marginBottom:6,borderLeft:`3px solid ${G.gold}`}}>
                    <div style={{color:G.muted,fontSize:10}}>{new Date(e.ts).toLocaleString()}</div>
                    <div style={{color:G.text,fontSize:13,marginTop:2}}>{e.text}</div>
                  </div>
                ))}
              </div>
              <Btn v="gold" onClick={save}>Save</Btn>
            </div>
          )}
        </div>
      </div>
    </div>
    {showMerge && (
      <MergeModal customer={c} allCustomers={allCustomers}
        onMerge={handleMerge} onClose={()=>setShowMerge(false)}/>
    )}
    </>
  );
}

// ── Customer Row ───────────────────────────────────────────
function CustomerRow({ customer, onClick, selected, onSelect }) {
  const high = custHigh(customer);
  const stage = custPrimaryStage(customer);
  const topItem = (customer.shipments||[])
    .flatMap(s=>s.items||[]).find(i=>i.estimate)?.item ||
    (customer.shipments||[]).flatMap(s=>s.items||[])[0]?.item || "—";
  const shipCount = (customer.shipments||[]).length;
  const lastLog = (customer.contactLog||[])[0]?.ts;

  return (
    <div style={{
      display:"grid",gridTemplateColumns:"36px 170px 1fr 110px 130px 100px",
      gap:10,padding:"10px 16px",
      background:selected?"#FFF8E1":G.card,
      borderBottom:`1px solid ${G.border}`,cursor:"pointer",alignItems:"center",
      borderLeft:selected?`3px solid ${G.gold}`:"3px solid transparent"
    }}
    onMouseEnter={e=>{ if(!selected) e.currentTarget.style.background=G.bg; }}
    onMouseLeave={e=>{ e.currentTarget.style.background=selected?"#FFF8E1":G.card; }}>
      {/* Checkbox */}
      <div onClick={e=>{e.stopPropagation();onSelect(customer.custId);}}
        style={{display:"flex",alignItems:"center",justifyContent:"center"}}>
        <div style={{
          width:16,height:16,borderRadius:3,cursor:"pointer",
          border:`2px solid ${selected?G.gold:G.border}`,
          background:selected?G.gold:"transparent",
          display:"flex",alignItems:"center",justifyContent:"center"
        }}>
          {selected && <span style={{color:"#fff",fontSize:11,lineHeight:1}}>✓</span>}
        </div>
      </div>
      <div onClick={onClick}>
        <div style={{color:G.text,fontSize:13,fontWeight:700,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>
          {customer.name||<span style={{color:G.muted}}>—</span>}
        </div>
        <div style={{color:G.muted,fontSize:10,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{customer.email}</div>
        {customer.phone&&<div style={{color:G.muted,fontSize:10}}>{fmtPhone(customer.phone)}</div>}
        {shipCount>1&&<div style={{color:G.blue,fontSize:10,marginTop:1}}>{shipCount} shipments</div>}
      </div>
      <div onClick={onClick} style={{color:G.muted,fontSize:12,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{topItem}</div>
      <div onClick={onClick}>
        <div style={{color:G.gold,fontWeight:800,fontSize:14}}>{high?fmt$(high):"—"}</div>
        {lastLog&&<div style={{color:G.muted,fontSize:10}}>contacted {daysSince(lastLog)}d ago</div>}
      </div>
      <div onClick={onClick}><Badge stage={stage}/></div>
      <div onClick={e=>e.stopPropagation()}>
        <ContactBtns customer={customer} size="sm"/>
      </div>
    </div>
  );
}

// ── Main ───────────────────────────────────────────────────
export default function SnappyGoldCRM() {
  const [unlocked, setUnlocked] = useState(false);
  const [custs, setCusts] = useState({});
  const [tab, setTab] = useState("followup");
  const [sel, setSel] = useState(null);
  const [search, setSearch] = useState("");
  const [stageF, setStageF] = useState("all");
  const [selectedIds, setSelectedIds] = useState(new Set());
  const [batchStage, setBatchStage] = useState("");

  useEffect(()=>{ if (unlocked) setCusts(initCustomers()); },[unlocked]);

  function saveCust(updated) {
    setCusts(prev=>{
      const next = {...prev,[updated.custId]:updated};
      persist(next); return next;
    });
  }
  function delCust(id) {
    setCusts(prev=>{
      const next = {...prev,[id]:{...prev[id],deleted:true}};
      persist(next); return next;
    });
    setSelectedIds(prev=>{ const n=new Set(prev); n.delete(id); return n; });
  }

  function toggleSelect(id) {
    setSelectedIds(prev=>{ const n=new Set(prev); n.has(id)?n.delete(id):n.add(id); return n; });
  }
  function selectAll() {
    if (selectedIds.size === display.length) {
      setSelectedIds(new Set());
    } else {
      setSelectedIds(new Set(display.map(c=>c.custId)));
    }
  }
  function batchDelete() {
    if (!window.confirm(`Delete ${selectedIds.size} customer(s)? This cannot be undone.`)) return;
    setCusts(prev=>{
      const next = {...prev};
      for (const id of selectedIds) next[id] = {...next[id], deleted:true};
      persist(next); return next;
    });
    setSelectedIds(new Set());
  }
  function batchChangeStage(stage) {
    if (!stage) return;
    setCusts(prev=>{
      const next = {...prev};
      for (const id of selectedIds) {
        const c = next[id];
        if (!c) continue;
        // Update primary (first) shipment stage
        const ships = [...(c.shipments||[])];
        if (ships.length) ships[0] = {...ships[0], stage};
        next[id] = {...c, shipments:ships};
      }
      persist(next); return next;
    });
    setSelectedIds(new Set());
    setBatchStage("");
  }

  const visible = useMemo(()=>Object.values(custs).filter(c=>!c.deleted),[custs]);

  const lists = useMemo(()=>{
    const byVal = (a,b)=>custHigh(b)-custHigh(a);
    const byStale = (a,b)=>{
      const at = (a.contactLog||[])[0]?.ts || a.timestamp;
      const bt = (b.contactLog||[])[0]?.ts || b.timestamp;
      return new Date(at)-new Date(bt);
    };
    return {
      // CS: outbound fulfilled but not yet received — check-in queue
      cs: visible.filter(c=>["outbound_fulfilled"].includes(custPrimaryStage(c))).sort(byVal),
      // Fulfill: ready to send OR already printed but not mailed
      fulfill: visible.filter(c=>["ready_to_fulfill","outbound_pending"].includes(custPrimaryStage(c))).sort(byVal),
      // Process: in-house — received through accepted
      process: visible.filter(c=>["received","inspected","offer_made","accepted"].includes(custPrimaryStage(c))).sort(byVal),
      // Follow Up: estimate only, hasn't completed address — re-engagement
      followup: visible.filter(c=>custPrimaryStage(c)==="estimate_only").sort(byStale),
      all: [...visible].sort(byVal),
    };
  },[visible]);

  const display = useMemo(()=>{
    let base = (search||stageF!=="all") ? lists.all : (lists[tab]||[]);
    if (search) {
      const q = search.toLowerCase();
      base = base.filter(c=>
        c.name?.toLowerCase().includes(q)||
        c.email?.toLowerCase().includes(q)||
        (c.phone||"").includes(q)||
        (c.shipments||[]).some(s=>(s.items||[]).some(i=>i.item?.toLowerCase().includes(q)))
      );
    }
    if (stageF!=="all") base = base.filter(c=>custPrimaryStage(c)===stageF);
    return base;
  },[lists,tab,search,stageF]);

  const stats = useMemo(()=>({
    total:    visible.length,
    fulfill:  lists.fulfill.length,
    process:  lists.process.length,
    closed:   visible.filter(c=>custPrimaryStage(c)==="purchase_complete").length,
    pipeline: visible.reduce((s,c)=>s+custHigh(c),0),
  }),[visible,lists]);

  if (!unlocked) return <PinGate onUnlock={()=>setUnlocked(true)}/>;

  const TABS = [
    {k:"followup", l:`Follow Up (${lists.followup.length})`},
    {k:"cs",       l:`CS (${lists.cs.length})`},
    {k:"fulfill",  l:`Fulfill (${lists.fulfill.length})`},
    {k:"process",  l:`Process (${lists.process.length})`},
    {k:"all",      l:`All (${visible.length})`},
  ];

  const selCust = sel ? (custs[sel.custId] || sel) : null;

  return (
    <div style={{minHeight:"100vh",background:G.bg,color:G.text,fontFamily:"system-ui,sans-serif"}}>
      {/* Topbar */}
      <div style={{background:G.card,borderBottom:`1px solid ${G.border}`,
        padding:"0 20px",display:"flex",alignItems:"center",gap:20,
        position:"sticky",top:0,zIndex:50,boxShadow:"0 1px 6px rgba(0,0,0,0.06)"}}>
        <div style={{padding:"13px 0",display:"flex",alignItems:"center",gap:8}}>
          <span style={{fontSize:20}}>🤖</span>
          <span style={{color:G.gold,fontWeight:800,fontSize:14,letterSpacing:1}}>SNAPPY GOLD</span>
          <span style={{color:G.muted,fontSize:11}}>CRM v3</span>
        </div>
        <div style={{flex:1}}/>
        <div style={{display:"flex",gap:18}}>
          {[
            ["Total",stats.total,G.text],
            ["Fulfill",stats.fulfill,SC.ready_to_fulfill],
            ["In Process",stats.process,SC.received],
            ["Closed",stats.closed,G.green],
            ["Pipeline","$"+Math.round(stats.pipeline/1000)+"K",G.gold],
          ].map(([l,v,color])=>(
            <div key={l} style={{textAlign:"center"}}>
              <div style={{color,fontWeight:800,fontSize:14}}>{v}</div>
              <div style={{color:G.muted,fontSize:9,textTransform:"uppercase",letterSpacing:0.5}}>{l}</div>
            </div>
          ))}
        </div>
      </div>

      {/* Tabs + search */}
      <div style={{background:G.card,borderBottom:`1px solid ${G.border}`,
        padding:"0 20px",display:"flex",alignItems:"center",
        position:"sticky",top:50,zIndex:49}}>
        {TABS.map(t=>(
          <button key={t.k} onClick={()=>{setTab(t.k);setSearch("");setStageF("all");}}
            style={{background:"none",border:"none",padding:"9px 13px",cursor:"pointer",
              fontSize:13,fontWeight:600,color:tab===t.k?G.gold:G.muted,
              borderBottom:tab===t.k?`2px solid ${G.gold}`:"2px solid transparent"}}>
            {t.l}
          </button>
        ))}
        <div style={{flex:1}}/>
        <div style={{display:"flex",gap:8,padding:"7px 0"}}>
          <input value={search} onChange={e=>setSearch(e.target.value)}
            placeholder="Name, email, phone, item…"
            style={{background:G.bg,color:G.text,border:`1px solid ${G.border}`,
              borderRadius:6,padding:"5px 12px",fontSize:12,width:220,outline:"none"}}
          />
          <select value={stageF} onChange={e=>setStageF(e.target.value)}
            style={{background:G.bg,color:G.text,border:`1px solid ${G.border}`,
              borderRadius:6,padding:"5px 10px",fontSize:12,cursor:"pointer"}}>
            <option value="all">All Stages</option>
            {STAGES.map(s=><option key={s} value={s}>{SL[s]}</option>)}
          </select>
        </div>
      </div>

      {/* Column headers */}
      <div style={{display:"grid",gridTemplateColumns:"36px 170px 1fr 110px 130px 100px",
        gap:10,padding:"6px 16px",background:"#EDE8DF",
        borderBottom:`1px solid ${G.border}`,position:"sticky",top:97,zIndex:48,alignItems:"center"}}>
        <div onClick={selectAll} style={{display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer"}}>
          <div style={{
            width:16,height:16,borderRadius:3,
            border:`2px solid ${selectedIds.size>0?G.gold:G.muted}`,
            background:selectedIds.size>0&&selectedIds.size===display.length?G.gold:"transparent",
            display:"flex",alignItems:"center",justifyContent:"center",flexShrink:0
          }}>
            {selectedIds.size===display.length&&display.length>0
              ? <span style={{color:"#fff",fontSize:10,lineHeight:1}}>✓</span>
              : selectedIds.size>0
              ? <span style={{color:G.gold,fontSize:12,lineHeight:1,fontWeight:700}}>−</span>
              : null}
          </div>
        </div>
        {["Customer","Top Item","Est High","Stage","Actions"].map(h=>(
          <div key={h} style={{color:G.muted,fontSize:10,fontWeight:700,
            textTransform:"uppercase",letterSpacing:0.5}}>{h}</div>
        ))}
      </div>

      {/* Batch action bar */}
      {selectedIds.size>0 && (
        <div style={{
          position:"sticky",top:123,zIndex:47,
          background:"#FFF8E1",borderBottom:`2px solid ${G.gold}`,
          padding:"8px 16px",display:"flex",gap:10,alignItems:"center",
          boxShadow:"0 2px 8px rgba(200,149,60,0.15)"
        }}>
          <span style={{color:G.gold,fontWeight:700,fontSize:13}}>
            {selectedIds.size} selected
          </span>
          <span style={{color:G.muted,fontSize:12}}>—</span>
          <Btn v="danger" onClick={batchDelete}>🗑 Delete All</Btn>
          <div style={{display:"flex",gap:6,alignItems:"center"}}>
            <select value={batchStage} onChange={e=>setBatchStage(e.target.value)}
              style={{background:G.bg,color:G.text,border:`1px solid ${G.border}`,
                borderRadius:5,padding:"4px 8px",fontSize:12,cursor:"pointer"}}>
              <option value="">Move to stage…</option>
              {STAGES.map(s=><option key={s} value={s}>{SL[s]}</option>)}
            </select>
            <Btn v="ghost" onClick={()=>batchChangeStage(batchStage)} disabled={!batchStage}>
              Apply
            </Btn>
          </div>
          <div style={{flex:1}}/>
          <Btn v="ghost" onClick={()=>setSelectedIds(new Set())}>Clear</Btn>
        </div>
      )}

      {/* Rows */}
      <div>
        {display.length===0 && (
          <div style={{padding:56,textAlign:"center",color:G.muted,fontSize:14}}>
            No leads in this view
          </div>
        )}
        {display.map(c=>(
          <CustomerRow key={c.custId} customer={c}
            onClick={()=>setSel(c)}
            selected={selectedIds.has(c.custId)}
            onSelect={toggleSelect}
          />
        ))}
      </div>

      {/* Detail */}
      {selCust && (
        <CustomerDetail
          customer={selCust}
          allCustomers={custs}
          onClose={()=>setSel(null)}
          onSave={c=>{saveCust(c);setSel(null);}}
          onDelete={id=>{delCust(id);setSel(null);}}
        />
      )}
    </div>
  );
}
